; 8086 Assembly Generated by Compiler
BITS 16
ORG 100h
SECTION .text
global _start
_start:
    CALL main
    MOV AX, 4C00h
    INT 21h


main:
    PUSH BP
    MOV BP, SP
    SUB SP, 6 ; Reserve locals
    MOV AX, 10
    MOV [BP-2], AX
    MOV SP, BP
    POP BP
    RET

