_print_int:
    PUSH BP
    MOV BP, SP
    MOV AX, [BP+4]
    ADD AX, '0' ; Hack: only works for single digit 0-9
    MOV DX, AX
    MOV AH, 02h
    INT 21h
    POP BP
    RET
